const amqplib = require('amqplib');
const connectionString = 'your-rabbitmq-connection-string';
const queueName = 'your-queue-name';

async function connectToRabbitMQ() {
  const connection = await amqplib.connect(connectionString);
  const channel = await connection.createChannel();
  
  await channel.assertQueue(queueName, { durable: true });
  
  console.log(' [*] Waiting for messages in %s. To exit press CTRL+C', queueName);
  
  channel.consume(queueName, async (msg) => {
    if (msg !== null) {
      const messageContent = msg.content.toString();
      try {
        const messageData = JSON.parse(messageContent);
        
        // Execute actions based on message type and payload
        switch (messageData.type) {
          case 'databaseQuery':
            await executeDatabaseQuery(messageData.payload);
            break;
          case 'systemCommand':
            await executeSystemCommand(messageData.payload);
            break;
          default:
            console.log('Unknown message type:', messageData.type);
        }
        
        channel.ack(msg);
      } catch (error) {
        console.error('Failed to process message:', error.message);
        channel.nack(msg, false, true);
      }
    }
  });
}

